import { useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { useAuth } from '../contexts/AuthContext'
import './Login.css'

const ROLE_HOME = {
  Employee: '/employee/dashboard',
  Manager: '/manager/dashboard',
  HR: '/hr/dashboard',
  'Super Admin': '/admin/dashboard',
}

